const langs = ['es','en','pt','de','fr','ar','he','it','ja','ko','ru','yi','zh'];

// ─────────────────────────────────────────────────────────────
// READ / PATCH / WRITE each language file
// ─────────────────────────────────────────────────────────────

for (const lang of langs) {
  const filePath = path.join(translationsDir, `${lang}.js`);
  let src = fs.readFileSync(filePath, 'utf8');

  // Find the last key-value line and insert after it
  const closeMatch = src.match(/\n(\s*)"[^"]+"\s*:\s*"[^"]*"\s*\n(\}\s*;?\s*)$/);
  if (!closeMatch) {
    console.error(`Could not parse end of ${lang}.js`);
    continue;
  }

  const newLines = Object.entries(newKeys)
    .filter(([key]) => !src.includes(`"${key}"`))
    .map(([key, vals]) => `  "${key}": "${(vals[lang] || vals.es).replace(/"/g, '\\"')}"`)
    .join(',\n');

  if (!newLines) {
    console.log(`${lang}.js — all keys already present, skipping.`);
    continue;
  }

  // Insert before closing brace
  src = src.replace(/(\n\s*\}\s*;?\s*)$/, `,\n${newLines}\n$1`);
  fs.writeFileSync(filePath, src, 'utf8');
  const count = newLines.split('\n').length;
  console.log(`✅ ${lang}.js — added ${count} keys`);
}

console.log('\n🎉 Done! All translation files updated.');
